const TOPIC_RES_LIST = "Henkelv2/Shanghai/Logistics/Production/State/Reservation_List";
const TOPIC_INVENTORY = "Henkelv2/Shanghai/Logistics/Internal/Ops/State/Inventory_Level";
const TOPIC_TASKS = "Henkelv2/Shanghai/Logistics/Production/State/Picking_Tasks";

let request = msg.payload;

// 1. Get Data
let resDB = global.get('reservation_db') || { items: [] };
let inventory = global.get('internal_stock_list') || [];
let taskDB = global.get('picking_task_db') || { items: [] };

// 2. Find the Reservation
let resIndex = resDB.items.findIndex(r => r.reservation_id === request.reservation_id);
if (resIndex === -1) {
    node.warn("FEFO Error: Reservation not found " + request.reservation_id);
    return null;
}
let reservation = resDB.items[resIndex];

// 3. FILTER Inventory
let candidates = inventory.filter(item =>
    item.sku === reservation.material_code &&
    item.status === "AVAILABLE"
);
// 4. SORT (FEFO)
candidates.sort((a, b) => {
    let dateA = a.expiry_date || 9999999999999;
    let dateB = b.expiry_date || 9999999999999;
    return dateA - dateB;
});

// 5. ALLOCATE & GENERATE TASKS
let needed = reservation.qty_required - (reservation.qty_allocated || 0);
let allocated_in_this_run = 0;

for (let batch of candidates) {
    if (needed <= 0) break;

    batch.status = "ALLOCATED";
    batch.allocated_to = reservation.reservation_id;

    let qtyTaken = batch.qty; // Assuming full batch allocation for now
    allocated_in_this_run += qtyTaken;
    needed -= qtyTaken;

    // --- NEW: CREATE PICK TASK ---
    // FIXED: Better ID generation
    let uniqueSuffix = Math.floor(Math.random() * 1000);
    let newTask = {
        task_id: "PICK-" + Date.now() + "-" + uniqueSuffix,
        reservation_id: reservation.reservation_id,
        order_id: reservation.order_id,
        batch_id: batch.batch_id,
        material_code: batch.sku,
        material_name: batch.desc, // Frontend expects this
        qty: qtyTaken,
        from_loc: batch.location || "ZONE-A",
        // FIXED: Don't hardcode if possible, default to line side
        to_loc: reservation.target_line || "LINE-SIDE-A",
        status: "PENDING",
        created_at: Date.now()
    };
    taskDB.items.unshift(newTask);
}

// 6. UPDATE Reservation Status
reservation.qty_allocated = (reservation.qty_allocated || 0) + allocated_in_this_run;
if (reservation.qty_allocated >= reservation.qty_required) {
    reservation.status = "ALLOCATED";
} else if (reservation.qty_allocated > 0) {
    reservation.status = "PARTIAL";
}

// 7. SAVE Globals
global.set('reservation_db', resDB);
global.set('internal_stock_list', inventory);
global.set('picking_task_db', taskDB);

// 8. PREPARE OUTPUTS
let msgRes = {
    topic: TOPIC_RES_LIST,
    payload: { version: "1.0", topics: [{ path: TOPIC_RES_LIST, type: "state", value: resDB }] }
};
let msgInv = {
    topic: TOPIC_INVENTORY,
    payload: { version: "1.0", topics: [{ path: TOPIC_INVENTORY, type: "state", value: { last_updated: Date.now(), stock_items: inventory } }] }
};
let msgTasks = {
    topic: TOPIC_TASKS,
    payload: { version: "1.0", topics: [{ path: TOPIC_TASKS, type: "state", value: taskDB }] }
};

return [msgRes, msgInv, msgTasks];

