let decision = msg.payload;
// Expected: { exception_id, action: 'ACCEPT'|'REJECT', note, resolver }

// 1. Get DBs
let exDB = global.get('exception_db') || { items: [] };
let inventory = global.get('internal_stock_list') || [];
let tasks = global.get('internal_task_queue') || { queue: [] };

// 2. Find Exception
let exIndex = exDB.items.findIndex(e => e.id === decision.exception_id);
if (exIndex === -1) {
    node.warn("Exception not found: " + decision.exception_id);
    return null;
}
let exception = exDB.items[exIndex];

// 3. APPLY LOGIC BASED ON DECISION
if (decision.action === 'ACCEPT') {
    // A. Unblock Inventory
    let stockItem = inventory.find(i => i.hu === exception.source_ref || i.batch_id === exception.source_ref);
    if (stockItem) {
        stockItem.status = "AVAILABLE";
        stockItem.notes = "Force Accepted by " + decision.resolver;
    }

    // B. Unblock/Create Task
    // (In a real system, we might need to regenerate a Putaway Task here)

    // C. Close Exception
    exception.status = "RESOLVED";
    exception.resolution = "ACCEPTED";

} else if (decision.action === 'REJECT') {
    // A. Mark Inventory as SCRAP/RETURN
    let stockItem = inventory.find(i => i.hu === exception.source_ref);
    if (stockItem) {
        stockItem.status = "RETURN_PENDING";
        stockItem.location = "OUTBOUND_DOCK";
    }

    // B. Close Exception
    exception.status = "RESOLVED";
    exception.resolution = "REJECTED";
}

// Remove resolved items from the active list (optional, or just keep them as closed)
