return [[msgLoad, msgShip, msgInv, msgDN]];

const TOPIC_PICK = 'Henkelv2/Shanghai/Logistics/Outbound/State/Picking_Queue';
const TOPIC_EX = 'Henkelv2/Shanghai/Logistics/Internal/Ops/State/Exceptions';

let action = msg.payload;
let taskId = action.task_id;

let pickQueue = global.get('outbound_picking_queue') || { tasks: [] };
let exDB = global.get('exception_db') || { items: [] };

let taskIdx = pickQueue.tasks.findIndex(t => t.task_id === taskId);
if (taskIdx !== -1) {
  pickQueue.tasks[taskIdx].status = 'SHORT';
}

let exEntry = {
  id: 'EX-' + Date.now(),
  type: 'SHORT_PICK',
  source_ref: taskId,
  description: action.reason || 'Short pick reported',
  expected_qty: action.expected_qty,
  actual_qty: action.actual_qty,
  status: 'OPEN',
  reported_by: action.operator,
  timestamp: Date.now()
};
exDB.items = exDB.items || [];
exDB.items.unshift(exEntry);
if (exDB.items.length > 50) exDB.items.pop();

global.set('outbound_picking_queue', pickQueue);
global.set('exception_db', exDB);

let msgPick = { topic: TOPIC_PICK, payload: { version: '1.0', topics: [{ path: TOPIC_PICK, type: 'state', value: pickQueue.tasks }] } };
let msgEx = { topic: TOPIC_EX, payload: { version: '1.0', topics: [{ path: TOPIC_EX, type: 'state', value: exDB }] } };

return [[msgPick, msgEx]];

const TOPIC_PLAN = "Henkelv2/Shanghai/Logistics/Internal/Ops/State/Inbound_Plan";

let data = msg.payload;
if (!data.doc_id) {
    node.warn("Delete_Inbound_Plan: missing doc_id");
    return null;
}

let inboundDB = global.get('internal_inbound_db') || { asns: [] };
let before = inboundDB.asns.length;
inboundDB.asns = inboundDB.asns.filter(o => o.id !== data.doc_id);

if (inboundDB.asns.length === before) {
    node.warn("Delete_Inbound_Plan: order not found — " + data.doc_id);
    return null;
}

global.set('internal_inbound_db', inboundDB);

msg.topic = TOPIC_PLAN;
msg.payload = {
    version: "1.0",
    topics: [{ path: TOPIC_PLAN, type: "state", value: inboundDB }]
};

return msg;
